    private static void PrewarmShaders()
    {
        ((CacheFile)Cache.Class.get()).onNewShader = new HlAction<RuntimeShader>(_ => { });

        var globalCache = Cache.Class.get();

        var outputArray = (ArrayObj)ArrayUtils.CreateDyn().array;
        outputArray.push(new Output.Value("output.color".ToHaxeString(), null));
        var tmpMgr = new ShaderManager(outputArray);


        string[] postShaderNames = new string[] {
            "shader.ColorMatrix",
            "shader.NormalMap",
            "shader.DirLighted",
            "shader.Outline",
            "shader.GradientMap",
            "shader.ColorLerpText",
            "shader.RGBReplace",
            "shader.GradientHiLo",
            "shader.FowApply",
            "shader.FowText",
            "shader.GlowKey",
            "shader.DefLighted",
            "shader.PointLight",
            "shader.RedirectToDisplace",
            "shader.ReflectIgnored",
            "shader.Foggy",
            "shader.CamFog",
            "shader.FowAdd",
            "shader.ColorMap"
        };


        var specialParams = new Dictionary<string, Action<Shader>>()
        {
            { "shader.GlowKey", s => { ((dynamic)s).animated__ = false; } },
            { "shader.Foggy", s => { ((dynamic)s).mode__ = 1; } }
        };


        var base2dFlags = new (bool pa, bool ka, bool uv, bool rel)[] {
        (false, false, true, true),
        (false, false, false, true),
        (false, true, true, true),
        (false, true, false, true),
        (false, false, true, false),
        (false, false, false, false)
    };

        foreach (var f in base2dFlags)
        {
            var base2d = new dc.shader.Base2d();
            base2d.pixelAlign__ = f.pa;
            base2d.killAlpha__ = f.ka;
            base2d.hasUVPos__ = f.uv;
            base2d.isRelative__ = f.rel;

            try { tmpMgr.compileShaders(new ShaderList(base2d, null)); } catch { }

            foreach (var postName in postShaderNames)
            {
                var postShader = ((CacheFile)globalCache).resolveShader(postName.ToHaxeString());
                if (postShader == null) continue;

                if (specialParams.TryGetValue(postName, out var setter))
                    setter(postShader);


                postShader.updateConstants(null);

                var chain = new ShaderList(postShader, new ShaderList(base2d, null));
                tmpMgr.compileShaders(chain);

            }
        }
    }




